import logging
import json
from datetime import datetime
from flask import request, g
import os

class WebLogger:
    def __init__(self, log_file="app.log", log_level=logging.INFO):
        self.logger = logging.getLogger('web_app')
        self.logger.setLevel(log_level)
        
        if not self.logger.handlers:
            file_handler = logging.FileHandler(log_file)
            file_handler.setLevel(log_level)
            
            formatter = logging.Formatter(
                '%(asctime)s - %(name)s - %(levelname)s - %(message)s'
            )
            file_handler.setFormatter(formatter)
            self.logger.addHandler(file_handler)
    
    def log_request(self, message, level=logging.INFO, **kwargs):
        """Log HTTP request with contextual information"""
        try:
            # Get request context
            request_info = {
                'timestamp': datetime.utcnow().isoformat(),
                'method': getattr(request, 'method', 'UNKNOWN'),
                'url': getattr(request, 'url', 'UNKNOWN'),
                'remote_addr': getattr(request, 'remote_addr', 'UNKNOWN'),
                'user_agent': getattr(request, 'user_agent', 'UNKNOWN'),
                'request_id': getattr(g, 'request_id', 'UNKNOWN'),
                'message': message,
                **kwargs
            }
            
            # Format log message
            log_message = (
                f"METHOD={request_info['method']} "
                f"URL={request_info['url']} "
                f"REMOTE_ADDR={request_info['remote_addr']} "
                f"USER_AGENT={request_info['user_agent']} "
                f"REQUEST_ID={request_info['request_id']} "
                f"MESSAGE={request_info['message']}"
            )
            
            # Add additional context if provided
            for key, value in kwargs.items():
                log_message += f" {key.upper()}={value}"
            
            # Log the message
            if level == logging.ERROR:
                self.logger.error(log_message)
            elif level == logging.WARNING:
                self.logger.warning(log_message)
            elif level == logging.DEBUG:
                self.logger.debug(log_message)
            else:
                self.logger.info(log_message)
                
        except Exception as e:
            # Fallback logging if request context is not available
            fallback_message = f"LOG_ERROR: {str(e)} - Original message: {message}"
            self.logger.error(fallback_message)

# Global logger instance
web_logger = WebLogger()

def log_request(message, level=logging.INFO, **kwargs):
    """Global function to log web requests"""
    web_logger.log_request(message, level, **kwargs)